import javax.jws.WebMethod;
import javax.jws.WebService;
import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.soap.MessageFactory;
import javax.xml.soap.SOAPBody;
import javax.xml.soap.SOAPException;
import javax.xml.soap.SOAPMessage;
import javax.xml.ws.Endpoint;
import java.io.StringReader;
import javax.xml.soap.*;
import org.w3c.dom.Document;
import org.w3c.dom.Element;
import org.w3c.dom.NodeList;
import org.xml.sax.InputSource;

@WebService
public class XMLProcessorService {

    @WebMethod
    public String processXML(String xmlPayload) {
        try {
            // Create a SOAP Message from the XML payload
            MessageFactory messageFactory = MessageFactory.newInstance();
            SOAPMessage soapMessage = messageFactory.createMessage(null,
                    new java.io.ByteArrayInputStream(xmlPayload.getBytes()));

            // Get the SOAP Body
            SOAPBody soapBody = soapMessage.getSOAPBody();

            // Prepare to parse the SOAP Body
            Document document = parseSOAPBody(soapBody);
            Element rootElement = document.getDocumentElement();

            // Process the XML document and handle nested entities
            processXMLDocument(rootElement);

            return "XML processed successfully";

        } catch (Exception e) {
            return "Failed to process XML: " + e.getMessage();
        }
    }

    private Document parseSOAPBody(SOAPBody soapBody) throws Exception {
        DocumentBuilderFactory dbf = DocumentBuilderFactory.newInstance();
        dbf.setNamespaceAware(true);
        DocumentBuilder db = dbf.newDocumentBuilder();
        InputSource is = new InputSource(new StringReader(soapBody.getTextContent()));
        return db.parse(is);
    }

    private void processXMLDocument(Element element) {
        // Process each child node recursively
        NodeList nodeList = element.getChildNodes();
        for (int i = 0; i < nodeList.getLength(); i++) {
            if (nodeList.item(i) instanceof Element) {
                Element childElement = (Element) nodeList.item(i);
                
                // Process child elements and handle nested entities
                // Example: print tag names
                System.out.println("Tag Name: " + childElement.getTagName());

                // Recursive call to handle deeply nested entities
                processXMLDocument(childElement);
            }
        }
    }

    public static void main(String[] args) {
        Endpoint.publish("http://localhost:8080/XMLProcessorService", new XMLProcessorService());
        System.out.println("SOAP Service is running at http://localhost:8080/XMLProcessorService");
    }
}